-- ============================================================
-- PHASE 11 : récits historiques du mode "Raconte" (carte).
-- Un texte par événement majeur, rédigé d'après le corpus de
-- sources de la base (grades A/B). Les événements sans récit
-- retombent sur leur résumé. Ton: documentaire, factuel.
-- ============================================================
CREATE TABLE IF NOT EXISTS narratives (
  event_id TEXT PRIMARY KEY REFERENCES events(event_id),
  text     TEXT NOT NULL
);

